VALUES
  ('elementary-10ced7e2-moex-00951', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-110-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '行政訴訟若以公法人之機關為被告，原則上應由那一個行政法院管轄？', '["由被告機關所在地之行政法院管轄", "由原告戶籍所在地之行政法院管轄", "由原告住所地之行政法院管轄", "一律以中央政府所在地之行政法院管轄"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:49+00:00", "source_pdf_sha1": "6a91a5eb9855", "answer_pdf_sha1": "413126103154", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00952', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-110-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '甲死亡後留下數筆存款及土地，其子女乙、丙、丁、戊為繼承人。甲遺囑中表示四大房子孫要團結，故 不得分割遺產。下列敘述何者正確？', '["乙、丙、丁、戊不能分割，要傳給後代變成祭祀公業", "乙為繼承人，得隨時請求分割遺產，丙、丁、戊不得拒絕", "乙、丙、丁、戊不能分割，但繼承開始10年後，得請求分割遺產", "乙、丙、丁、戊於甲死後，因遺囑禁止分割，依民法規定，遺產於20年內均不得分割"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:49+00:00", "source_pdf_sha1": "6a91a5eb9855", "answer_pdf_sha1": "413126103154", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00953', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-110-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '下列關於民事訴訟代理人之敘述，何者正確？', '["簡易事件第二審之訴訟代理人，應委任具有教育部認證之法律相關科系獲碩士學位以上者，擔任訴訟 代理人。該訴訟代理人之酬金，由國庫墊之", "訴訟代理人就其受委任之事件有為一切訴訟行為之權。但捨棄、認諾、撤回、和解、提起反訴、上訴 或再審之訴及選任代理人，非受特別委任不得為之", "訴訟代理人有二人以上者，應共同代理當事人，不得單獨為之", "訴訟代理人為當事人聲請訴之追加、變更或提起反訴時，應先以書面聲請法院得審判長同意後，並為 當事人先墊付訴訟費用"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:49+00:00", "source_pdf_sha1": "6a91a5eb9855", "answer_pdf_sha1": "413126103154", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00954', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-110-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '關於自治條例之敘述，下列何者錯誤？', '["應分別冠以各該地方自治團體之名稱", "在直轄市為直轄市法規", "自治條例在縣稱縣規章", "自治條例在鄉稱鄉規程"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:49+00:00", "source_pdf_sha1": "6a91a5eb9855", "answer_pdf_sha1": "413126103154", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00955', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-110-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '關於民事支付命令之敘述，下列何者正確？', '["債權人之請求須證明", "債務人於法定期間合法提出異議，支付命令之效力不受影響", "債務人未於法定期間合法提出異議，支付命令不得作為執行名義", "支付命令之異議，得不附理由"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:49+00:00", "source_pdf_sha1": "6a91a5eb9855", "answer_pdf_sha1": "413126103154", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00956', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-110-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '民事訴訟當事人如因不應歸責於己之事由，遲誤上訴期間，依法得如何尋求救濟？', '["逕向上級法院提起上訴", "向原法院聲請延長期間", "向原法院聲請回復原狀", "向原法院聲請再審"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:49+00:00", "source_pdf_sha1": "6a91a5eb9855", "answer_pdf_sha1": "413126103154", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00957', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-110-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '有關親屬之親系與親等之規定，對於自己與繼母之表兄的親系與親等，下列敘述何者正確？', '["無親屬關係", "旁系姻親三親等", "旁系姻親四親等", "旁系姻親五親等"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:49+00:00", "source_pdf_sha1": "6a91a5eb9855", "answer_pdf_sha1": "413126103154", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00958', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-110-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '關於民法規定正當防衛、緊急避難與自助行為之敘述，下列何者正確？', '["因避免自己之生命身體受到急迫危險所為之自助行為，致他人財產受新臺幣50萬元以下之損害者，不 負賠償責任", "因避免自己之配偶、或直系血親三親等內之親屬，受到身體或自由上之急迫危險所為之家族集體自助 行為，致生他人之生命身體或財產損害者，不負賠償責任", "對於現時或24小時內已發生之不法的人身侵害，為防衛自己、配偶或家屬之權利所為的行為，不負損 害賠償之責", "為保護自己權利，對於他人之自由或財產施以拘束、押收或毀損者，不負損害賠償之責。但以不及受 法院或其他有關機關援助，並非於其時為之，則請求權不得實行或其實行顯有困難者為限"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:49+00:00", "source_pdf_sha1": "6a91a5eb9855", "answer_pdf_sha1": "413126103154", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00959', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-110-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '依現行民法之規定，19歲之甲因很想購買全新機車，擅自將父親乙贈與之老舊A機車拋棄。甲對A機車 之拋棄行為效力如何？', '["有效，不得撤銷", "無效", "效力未定", "有效，得撤銷"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:49+00:00", "source_pdf_sha1": "6a91a5eb9855", "answer_pdf_sha1": "413126103154", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00960', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-110-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '甲欲購買乙的二手筆記型電腦，交付新臺幣（下同）5,000元定金予乙，約定5日後交貨。關於定金之敘 述，下列何者錯誤？', '["甲交付定金予乙，依民法規定，乙受有定金時，推定其契約成立", "若甲於交付定金後，現場檢視該筆電時，不慎摔毀該筆電，則甲不得請求返還定金", "若乙交付筆電前，不慎摔毀該筆電，則乙應返還1萬元給甲", "若乙交付筆電前，筆電因無名火而燒燬，甲不得請求返還定金"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:49+00:00", "source_pdf_sha1": "6a91a5eb9855", "answer_pdf_sha1": "413126103154", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL)
